"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

interface GradientCardProps extends React.HTMLAttributes<HTMLDivElement> {
  glowColor?: "particle" | "electric" | "none"
}

const GradientCard = React.forwardRef<HTMLDivElement, GradientCardProps>(
  ({ className, glowColor = "particle", children, ...props }, ref) => (
    <div
      ref={ref}
      className={cn(
        "relative rounded-xl p-px",
        "bg-gradient-to-br",
        glowColor === "particle" && "from-particle-600 via-particle-800 to-particle-950",
        glowColor === "electric" && "from-electric-500 via-particle-700 to-particle-950",
        glowColor === "none" && "from-neutral-700 to-neutral-900",
        className
      )}
      {...props}
    >
      <div className="rounded-[11px] bg-particle-950/90 backdrop-blur-sm p-6">
        {children}
      </div>
    </div>
  )
)
GradientCard.displayName = "GradientCard"

export { GradientCard }
